package graphql

import (
	"context"
	"fmt"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// RunsStateProvider is the optional sub-interface a StateProvider may
// implement to back the runs/run queries.
// Kept separate from StateProvider so test stubs that don't need runs
// continue to compile.
type RunsStateProvider interface {
	GetRunsGraphQL(projectID string, filter RunFilter) []*Run
	GetRunGraphQL(id string) (*Run, bool)
}

// RunDetailStateProvider is the optional sub-interface for the Story 16
// run-detail surfaces (tool calls + bundle file resolver). Kept separate from
// RunsStateProvider so legacy stubs continue to compile.
type RunDetailStateProvider interface {
	GetRunToolCallsGraphQL(id string) []*RunToolCall
	GetRunBundleFileGraphQL(id, path string) (*RunBundleFileContent, bool)
}

const runDetailViewEventKind = "run_detail_view"

// RunFilter holds the optional filter args for Query.runs.
type RunFilter struct {
	Layer   *RunLayer
	BeadID  string
	Status  string
	Harness string
}

// Runs is the resolver for the runs field.
func (r *queryResolver) Runs(ctx context.Context, projectID *string, layer *RunLayer, beadID *string, status *string, harness *string, first *int, after *string) (*RunConnection, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return emptyRunConnection(), nil
	}
	pid := ""
	if projectID != nil {
		pid = *projectID
	}
	filter := RunFilter{Layer: layer}
	if beadID != nil {
		filter.BeadID = *beadID
	}
	if status != nil {
		filter.Status = *status
	}
	if harness != nil {
		filter.Harness = *harness
	}
	all := provider.GetRunsGraphQL(pid, filter)
	return runConnectionFrom(all, first, after), nil
}

// Run is the resolver for the run field.
func (r *queryResolver) Run(ctx context.Context, id string) (*Run, error) {
	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return nil, nil
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return nil, nil
	}
	projectID, ok := r.projectIDForWorkingDir(wd)
	if !ok {
		return nil, nil
	}
	run, ok := provider.GetRunGraphQL(id)
	if !ok {
		return nil, nil
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) != projectID {
		return nil, nil
	}
	r.recordRunDetailView(ctx, run)
	return run, nil
}

func (r *queryResolver) projectIDForWorkingDir(workingDir string) (string, bool) {
	if r.State == nil || workingDir == "" {
		return "", false
	}
	for _, proj := range r.State.GetProjectSnapshots(false) {
		if proj.Path == workingDir {
			return proj.ID, true
		}
	}
	return "", false
}

// recordRunDetailView appends the canonical run_detail_view bead audit event
// the first time a project-scoped run detail is resolved for a specific run.
// Duplicate loads of the same run id are ignored, but distinct runs on the
// same bead remain auditable.
func (r *queryResolver) recordRunDetailView(ctx context.Context, run *Run) {
	if run == nil || run.BeadID == nil || strings.TrimSpace(*run.BeadID) == "" {
		return
	}
	if run.ProjectID == nil || strings.TrimSpace(*run.ProjectID) == "" {
		return
	}
	wd := r.workingDir(ctx)
	if wd == "" {
		return
	}
	if projectID, ok := r.projectIDForWorkingDir(wd); !ok || projectID != strings.TrimSpace(*run.ProjectID) {
		return
	}

	store := bead.NewStore(filepath.Join(wd, ".ddx"))
	if existing, err := store.EventsByKind(*run.BeadID, runDetailViewEventKind); err == nil {
		for _, ev := range existing {
			if strings.Contains(ev.Body, "run_id="+run.ID) {
				return
			}
		}
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	body := fmt.Sprintf(
		"project_id=%s run_id=%s layer=%s visibility=project_membership",
		*run.ProjectID,
		run.ID,
		run.Layer,
	)
	_ = store.AppendEvent(*run.BeadID, bead.BeadEvent{
		Kind:    runDetailViewEventKind,
		Summary: "run detail viewed",
		Body:    body,
		Actor:   identity.actor,
		Source:  "graphql:run",
	})
}

// RunToolCalls is the resolver for the runToolCalls field. Returns the
// normalized tool-call entries persisted at drain time, paginated by
// sequence. Returns an empty connection (not an error) for unknown ids or
// when the backing state provider does not implement RunDetailStateProvider.
func (r *queryResolver) RunToolCalls(ctx context.Context, id string, first *int, after *string) (*RunToolCallConnection, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return emptyRunToolCallConnection(), nil
	}
	calls := provider.GetRunToolCallsGraphQL(id)
	return runToolCallConnectionFrom(calls, first, after), nil
}

// RunBundleFile is the resolver for the runBundleFile field. Returns nil
// (not an error) when the path fails canonical-path / whitelist checks or
// the file is not present — the GraphQL response treats nil as 404.
func (r *queryResolver) RunBundleFile(ctx context.Context, id string, path string) (*RunBundleFileContent, error) {
	provider, ok := r.State.(RunDetailStateProvider)
	if !ok {
		return nil, nil
	}
	out, ok := provider.GetRunBundleFileGraphQL(id, path)
	if !ok {
		return nil, nil
	}
	return out, nil
}

func emptyRunToolCallConnection() *RunToolCallConnection {
	return &RunToolCallConnection{Edges: []*RunToolCallEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
}

func runToolCallConnectionFrom(calls []*RunToolCall, first *int, after *string) *RunToolCallConnection {
	all := make([]*RunToolCallEdge, len(calls))
	ids := make([]string, len(calls))
	for i, c := range calls {
		all[i] = &RunToolCallEdge{Node: c, Cursor: encodeStableCursor(c.ID)}
		ids[i] = c.ID
	}
	startIdx, _ := stablePageBounds(ids, after, nil)
	slice := all[startIdx:]
	truncByFirst := false
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
		truncByFirst = true
	}
	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0,
		HasNextPage:     truncByFirst,
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}
	return &RunToolCallConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
}

func emptyRunConnection() *RunConnection {
	return &RunConnection{Edges: []*RunEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
}

func runConnectionFrom(runs []*Run, first *int, after *string) *RunConnection {
	all := make([]*RunEdge, len(runs))
	ids := make([]string, len(runs))
	for i, r := range runs {
		all[i] = &RunEdge{Node: r, Cursor: encodeStableCursor(r.ID)}
		ids[i] = r.ID
	}
	startIdx, _ := stablePageBounds(ids, after, nil)
	slice := all[startIdx:]
	truncByFirst := false
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
		truncByFirst = true
	}
	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0,
		HasNextPage:     truncByFirst,
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}
	return &RunConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
}

// ApplyRunFilter applies the filter to a list of runs. Exported so state_runs.go can call it.
func ApplyRunFilter(in []*Run, filter RunFilter) []*Run {
	return applyRunFilter(in, filter)
}

// applyRunFilter applies the filter to a list of runs.
func applyRunFilter(in []*Run, filter RunFilter) []*Run {
	if len(in) == 0 {
		return in
	}
	if filter.Layer == nil && filter.BeadID == "" && filter.Status == "" && filter.Harness == "" {
		return in
	}
	out := in[:0:0]
	for _, r := range in {
		if filter.Layer != nil && r.Layer != *filter.Layer {
			continue
		}
		if filter.BeadID != "" {
			if r.BeadID == nil || *r.BeadID != filter.BeadID {
				continue
			}
		}
		if filter.Status != "" {
			if !strings.EqualFold(r.Status, filter.Status) {
				continue
			}
		}
		if filter.Harness != "" {
			if r.Harness == nil || *r.Harness != filter.Harness {
				continue
			}
		}
		out = append(out, r)
	}
	return out
}

package server

// TC-GQL-SUB-001: workerProgress subscription streams real events over WebSocket.
//
// Integration test that opens a real WebSocket client, sends a
// workerProgress subscription, drives fake progress events through a
// stub ProgressSubscriber, and verifies all events arrive in order.

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/DocumentDrivenDX/ddx/internal/agent"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
	"github.com/gorilla/websocket"
)

// newGraphQLHandlerWithWorkers creates an HTTP handler backed by the given
// server state but with a custom ProgressSubscriber injected — used in tests
// to drive fake progress events without a live worker.
func newGraphQLHandlerWithWorkers(srv *Server, sub ddxgraphql.ProgressSubscriber) http.Handler {
	gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers: &ddxgraphql.Resolver{
			State:      srv.state,
			WorkingDir: srv.WorkingDir,
			Workers:    sub,
		},
		Directives: ddxgraphql.DirectiveRoot{},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	gqlSrv.AddTransport(transport.Websocket{
		Upgrader: websocket.Upgrader{
			CheckOrigin: func(r *http.Request) bool { return true },
		},
	})
	return gqlSrv
}

// stubProgressSubscriber is a fake ProgressSubscriber that returns a
// pre-loaded channel of events.
type stubProgressSubscriber struct {
	ch  chan agent.ProgressEvent
	sub func()
}

func (s *stubProgressSubscriber) SubscribeProgress(_ string) (<-chan agent.ProgressEvent, func()) {
	return s.ch, s.sub
}

// wsMsg is a minimal graphql-transport-ws protocol message.
type wsMsg struct {
	ID      string          `json:"id,omitempty"`
	Type    string          `json:"type"`
	Payload json.RawMessage `json:"payload,omitempty"`
}

// TC-GQL-SUB-001: workerProgress subscription delivers events via WebSocket.
func TestGraphQLWorkerProgressSubscription(t *testing.T) {
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)
	t.Setenv("DDX_NODE_NAME", "gql-sub-test-node")

	workDir := setupTestDir(t)
	srv := New(":0", workDir)

	// Build a stub subscriber with 3 pre-loaded events.
	eventCh := make(chan agent.ProgressEvent, 8)
	now := time.Now().UTC()
	events := []agent.ProgressEvent{
		{EventID: "evt-1", WorkerID: "worker-abc", Phase: "loop.start", TS: now, Message: "worker started"},
		{EventID: "evt-2", WorkerID: "worker-abc", Phase: "bead.claimed", BeadID: "bead-xyz", TS: now.Add(time.Second)},
		{EventID: "evt-3", WorkerID: "worker-abc", Phase: "bead.result", BeadID: "bead-xyz", TS: now.Add(2 * time.Second), Message: "execution complete"},
	}
	for _, e := range events {
		eventCh <- e
	}
	close(eventCh)

	stub := &stubProgressSubscriber{
		ch:  eventCh,
		sub: func() {},
	}

	// Override the Workers field on the server's resolver via a test-only
	// handler that injects the stub.
	ts := httptest.NewServer(newGraphQLHandlerWithWorkers(srv, stub))
	defer ts.Close()

	// Connect via WebSocket using the graphql-transport-ws subprotocol.
	wsURL := "ws" + strings.TrimPrefix(ts.URL, "http") + "/graphql"
	conn, _, err := websocket.DefaultDialer.Dial(wsURL, map[string][]string{
		"Sec-WebSocket-Protocol": {"graphql-transport-ws"},
	})
	if err != nil {
		t.Fatalf("WebSocket dial: %v", err)
	}
	defer conn.Close()

	send := func(msg wsMsg) {
		t.Helper()
		data, _ := json.Marshal(msg)
		if err := conn.WriteMessage(websocket.TextMessage, data); err != nil {
			t.Fatalf("WebSocket write: %v", err)
		}
	}

	recv := func() wsMsg {
		t.Helper()
		conn.SetReadDeadline(time.Now().Add(5 * time.Second))
		_, data, err := conn.ReadMessage()
		if err != nil {
			t.Fatalf("WebSocket read: %v", err)
		}
		var msg wsMsg
		if err := json.Unmarshal(data, &msg); err != nil {
			t.Fatalf("unmarshal: %v", err)
		}
		return msg
	}

	// graphql-transport-ws handshake.
	send(wsMsg{Type: "connection_init"})
	ack := recv()
	if ack.Type != "connection_ack" {
		t.Fatalf("expected connection_ack, got %q", ack.Type)
	}

	// Subscribe.
	queryPayload, _ := json.Marshal(map[string]string{
		"query": `subscription { workerProgress(workerID: "worker-abc") { eventID workerID phase logLine beadID } }`,
	})
	send(wsMsg{ID: "1", Type: "subscribe", Payload: queryPayload})

	// Collect events until "complete".
	type eventData struct {
		Data struct {
			WP struct {
				EventID  string  `json:"eventID"`
				WorkerID string  `json:"workerID"`
				Phase    string  `json:"phase"`
				LogLine  *string `json:"logLine"`
				BeadID   *string `json:"beadID"`
			} `json:"workerProgress"`
		} `json:"data"`
	}

	var received []eventData
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	for {
		select {
		case <-ctx.Done():
			t.Fatalf("timed out waiting for subscription events; got %d so far", len(received))
		default:
		}
		msg := recv()
		switch msg.Type {
		case "next":
			var payload struct {
				Data struct {
					WP struct {
						EventID  string  `json:"eventID"`
						WorkerID string  `json:"workerID"`
						Phase    string  `json:"phase"`
						LogLine  *string `json:"logLine"`
						BeadID   *string `json:"beadID"`
					} `json:"workerProgress"`
				} `json:"data"`
			}
			if err := json.Unmarshal(msg.Payload, &payload); err != nil {
				t.Fatalf("unmarshal next payload: %v", err)
			}
			received = append(received, eventData{Data: payload.Data})
		case "complete":
			goto done
		case "ping":
			send(wsMsg{Type: "pong"})
		default:
			t.Logf("unexpected message type: %s", msg.Type)
		}
	}
done:

	if len(received) != 3 {
		t.Fatalf("expected 3 events, got %d", len(received))
	}

	checks := []struct {
		phase   string
		logLine *string
		beadID  *string
	}{
		{"loop.start", ptr("worker started"), nil},
		{"bead.claimed", nil, ptr("bead-xyz")},
		{"bead.result", ptr("execution complete"), ptr("bead-xyz")},
	}
	for i, chk := range checks {
		wp := received[i].Data.WP
		if wp.Phase != chk.phase {
			t.Errorf("event[%d]: phase=%q want %q", i, wp.Phase, chk.phase)
		}
		if wp.WorkerID != "worker-abc" {
			t.Errorf("event[%d]: workerID=%q want worker-abc", i, wp.WorkerID)
		}
		if chk.logLine != nil {
			if wp.LogLine == nil || *wp.LogLine != *chk.logLine {
				t.Errorf("event[%d]: logLine=%v want %v", i, wp.LogLine, chk.logLine)
			}
		} else if wp.LogLine != nil {
			t.Errorf("event[%d]: expected no logLine, got %q", i, *wp.LogLine)
		}
		if chk.beadID != nil {
			if wp.BeadID == nil || *wp.BeadID != *chk.beadID {
				t.Errorf("event[%d]: beadID=%v want %v", i, wp.BeadID, chk.beadID)
			}
		} else if wp.BeadID != nil {
			t.Errorf("event[%d]: expected no beadID, got %q", i, *wp.BeadID)
		}
	}
}

