"Expected op_not_granted, got: ${BODY}\\\"\\n+else\\n+    info \\\"Test 3: skipped (python3 not available)\\\"\\n+fi\\n+\\n+# ── Test 4: gRPC composite header ─────────────────────────────────────────────\\n+if command -v grpcurl \u0026\u003e/dev/null; then\\n+    info \\\"Test 4: gRPC composite x-axon-tenant-database header\\\"\\n+    GRPC_RESP=$(grpcurl \\\\\\n+        -plaintext \\\\\\n+        -H \\\"x-axon-tenant-database: ${TENANT}:${DATABASE}\\\" \\\\\\n+        -d '{\\\"collection\\\":\\\"items\\\",\\\"id\\\":\\\"grpc-smoke-01\\\",\\\"data_json\\\":\\\"{\\\\\\\"x\\\\\\\":4}\\\",\\\"actor\\\":\\\"smoke\\\"}' \\\\\\n+        \\\"127.0.0.1:${AXON_GRPC_PORT}\\\" axon.v1.AxonService/CreateEntity 2\u003e\u00261)\\n+    echo \\\"$GRPC_RESP\\\" | grep -q '\\\"id\\\": \\\"grpc-smoke-01\\\"' \u0026\u0026 \\\\\\n+        pass \\\"gRPC composite header → entity created\\\" || \\\\\\n+        fail \\\"gRPC composite header failed: ${GRPC_RESP}\\\"\\n+else\\n+    info \\\"Test 4: skipped (grpcurl not installed)\\\"\\n+fi\\n+\\n+echo \\\"\\\"\\n+pass \\\"All cutover smoke tests passed.\\\"\",\"is_error\":false}]},\"parent_tool_use_id\":null,\"session_id\":\"0a9f1446-c2e0-4db8-b50e-318c50111461\",\"uuid\":\"65d8c9dc-8955-4bd1-af6e-a483f0e80253\",\"timestamp\":\"2026-04-16T01:10:06.715Z\",\"tool_use_result\":{\"stdout\":\"diff --git a/crates/axon-api/src/handler.rs b/crates/axon-api/src/handler.rs\\nindex bef68e8..fea605f 100644\\n--- a/crates/axon-api/src/handler.rs\\n+++ b/crates/axon-api/src/handler.rs\\n@@ -1,3 +1,4 @@\\n+use std::cell::RefCell;\\n use std::collections::{HashMap, HashSet, VecDeque};\\n use std::sync::{Arc, Mutex, MutexGuard};\\n use std::time::{SystemTime, UNIX_EPOCH};\\n@@ -11,6 +12,35 @@ fn now_ns() -\u003e u64 {\\n         .unwrap_or(0)\\n }\\n \\n+// ── ADR-018 attribution thread-local ─────────────────────────────────────────\\n+\\n+thread_local! {\\n+    /// Holds the `AuditAttribution` to stamp onto the next audit write.\\n+    ///\\n+    /// Set 