per request by [`auth::AuthContext`] and\\n6\\t//! injected as a typed extension.  Three modes are supported:\\n7\\t//!\\n8\\t//! | Mode | Flag | Actor | Role |\\n9\\t//! |------|------|-------|------|\\n10\\t//! | `NoAuth` | `--no-auth` | `\\\"anonymous\\\"` | Admin |\\n11\\t//! | `Tailscale` | *(default)* | node name | from ACL tags |\\n12\\t//! | `Guest` | `--guest-role \u003crole\u003e` | `\\\"guest\\\"` | configured role |\\n13\\t//!\\n14\\t//! In `Tailscale` mode the server contacts the local Tailscale daemon over its\\n15\\t//! Unix socket (`/run/tailscale/tailscaled.sock` by default) and calls\\n16\\t//! `/localapi/v0/whois?addr=\u003cpeer\u003e` to resolve the connecting node's identity.\\n17\\t//! Resolved identities are cached by peer IP for the duration of\\n18\\t//! `--auth-cache-ttl-secs` (default 60 s).\\n19\\t//!\\n20\\t//! ACL tag → role mapping:\\n21\\t//! - `tag:axon-admin` → [`Role::Admin`]\\n22\\t//! - `tag:axon-write` / `tag:axon-agent` → [`Role::Write`]\\n23\\t//! - `tag:axon-read` → [`Role::Read`]\\n24\\t//! - no matching tag → `--tailscale-default-role` (default `read`)\\n25\\t//!\\n26\\t//! Connections that are not on the tailnet are rejected with HTTP 401 / gRPC\\n27\\t//! `UNAUTHENTICATED`.  If the Tailscale daemon is unreachable the server\\n28\\t//! returns HTTP 503 / gRPC `UNAVAILABLE`.\\n29\\t//!\\n30\\t//! # Request flow\\n31\\t//!\\n32\\t//! ```text\\n33\\t//! TCP accept\\n34\\t//!   └─ authenticate_http_request  (gateway.rs middleware)\\n35\\t//!        ├─ AuthContext::resolve_peer  →  Identity\\n36\\t//!        └─ insert Identity into request extensions\\n37\\t//!             └─ route handler\\n38\\t//!                  ├─ extract Extension\u003cIdentity\u003e\\n39\\t//!                  ├─ identity.require_read() / require_write() / require_admin()\\n40\\t//!                  └─ handler logic\\n41\\t//! ```\\n42\\t//!\\n43\\t//! gRPC follows the same pattern via [`service::AxonServiceImpl::authorize`].\\n44\\tpub mod actor_scope;\\n45\\tpub mod auth;\\n46\\tmod collection_listing;\\n47\\tpub(crate) mod embedded_ui;\\n48\\tpub mod control_plane;\\n49\\tpub mod control_plane_routes;\\n50\\tpub mod cors_config;\\n51\\tpub mod user_roles;\\n52\\tpub mod gateway;\\n53\\tpub mod idempotency;\\n54\\tpub(crate) mod mcp_http;\\n55\\tpub mod mcp_stdio;\\n56\\tpub mod rate_limit;\\n57\\tpub mod schema_registry;\\n58\\tpub mod serve;\\n59\\tpub mod service;\\n60\\tpub mod tenant_router;\\n61\\t\\n62\\tpub use auth::{AuthContext, AuthMode, Identity, Role};\\n63\\tpub use mcp_stdio::run_mcp_stdio;\\n64\\tpub use service::AxonServiceImpl;\\n65\\t\"}]},\"parent_tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"b2e10ba8-f883-42a2-b408-1004661a2ce3\",\"timestamp\":\"2026-04-15T01:30:53.127Z\"}\n{\"type\":\"system\",\"subtype\":\"task_progress\",\"task_id\":\"ab7893c6e8bebbea1\",\"tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"description\":\"Reading crates/axon-server/Cargo.toml\",\"usage\":{\"total_tokens\":15407,\"tool_uses\":7,\"duration_ms\":3086},\"last_tool_name\":\"Read\",\"uuid\":\"147d8046-275e-4145-a373-e80743a6baf4\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-haiku-4-5-20251001\",\"id\":\"msg_01HVup1F1heBi8gDVfYDPYDe\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_01McyPQnQ5TTPJuHkuJPEXhZ\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-server/Cargo.toml\"},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":3,\"cache_creation_input_tokens\":15380,\"cache_read_input_tokens\":0,\"cache_creation\":{\"ephemeral_5m_input_tokens\":15380,\"ephemeral_1h_input_tokens\":0},\"output_tokens\":3,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"co