\t                    \u0026default_namespace.schema,\\n1099\\t                ],\\n1100\\t            ))?;\\n1101\\t        }\\n1102\\t        self.block(self.client.execute(\\n1103\\t            \\\"DELETE FROM schemas\\n1104\\t                 WHERE collection = $1 AND database_name = $2 AND schema_name = $3\\\",\\n1105\\t            \u0026[\\n1106\\t                \u0026key.collection.as_str(),\\n1107\\t                \u0026key.namespace.database,\\n1108\\t                \u0026key.namespace.schema,\\n1109\\t            ],\\n1110\\t        ))?;\\n1111\\t        if raw_collection != key.collection.as_str() {\\n1112\\t            self.block(self.client.execute(\\n1113\\t                \\\"DELETE FROM schemas\\n1114\\t                     WHERE collection = $1\\n1115\\t                       AND ((database_name = $2 AND schema_name = $3)\\n1116\\t                            OR (database_name = $4 AND schema_name = $5))\\\",\\n1117\\t                \u0026[\\n1118\\t                    \u0026raw_collection,\\n1119\\t                    \u0026key.namespace.database,\\n1120\\t                    \u0026key.namespace.schema,\\n1121\\t                    \u0026default_namespace.database,\\n1122\\t                    \u0026default_namespace.schema,\\n1123\\t                ],\\n1124\\t            ))?;\\n1125\\t        }\\n1126\\t        self.block(self.client.execute(\\n1127\\t            \\\"DELETE FROM collections\\n1128\\t                 WHERE name = $1 AND database_name = $2 AND schema_name = $3\\\",\\n1129\\t            \u0026[\\n1130\\t                \u0026key.collection.as_str(),\\n1131\\t                \u0026key.namespace.database,\\n1132\\t                \u0026key.namespace.schema,\\n1133\\t            ],\\n1134\\t        ))?;\\n1135\\t        if raw_collection != key.collection.as_str() {\\n1136\\t            self.block(self.client.execute(\\n1137\\t                \\\"DELETE FROM collections\\n1138\\t                     WHERE name = $1\\n1139\\t                       AND ((database_name = $2 AND schema_name = $3)\\n1140\\t                            OR (database_name = $4 AND schema_name = $5))\\\",\\n1141\\t                \u0026[\\n1142\\t                    \u0026raw_collection,\\n1143\\t                    \u0026key.namespace.database,\\n1144\\t                    \u0026key.namespace.schema,\\n1145\\t                    \u0026default_namespace.database,\\n1146\\t                    \u0026default_namespace.schema,\\n1147\\t                ],\\n1148\\t            ))?;\\n1149\\t        }\\n1150\\t        Ok(())\\n1151\\t    }\\n1152\\t\\n1153\\t    fn list_collections(\u0026self) -\u003e Result\u003cVec\u003cCollectionId\u003e, AxonError\u003e {\\n1154\\t        let rows = self.block(self.client.query(\\n1155\\t            \\\"SELECT name FROM collections\\n1156\\t                 ORDER BY database_name ASC, schema_name ASC, name ASC\\\",\\n1157\\t            \u0026[],\\n1158\\t        ))?;\\n1159\\t\\n1160\\t        Ok(rows\\n1161\\t            .iter()\\n1162\\t            .map(|row| {\\n1163\\t                let name: String = row.get(\\\"name\\\");\\n1164\\t                CollectionId::new(name)\\n1165\\t            })\\n1166\\t            .collect())\\n1167\\t    }\\n1168\\t\\n1169\\t    fn collection_registered_in_namespace(\\n1170\\t        \u0026self,\\n1171\\t        collection: \u0026CollectionId,\\n1172\\t        namespace: \u0026Namespace,\\n1173\\t    ) -\u003e Result\u003cbool, AxonError\u003e {\\n1174\\t        self.collection_exists_in_namespace(collection, namespace)\\n1175\\t    }\\n1176\\t}\\n1177\\t\\n1178\\t// ── Per-tenant PostgreSQL provisioning ───────────────────────────────────────\\n1179\\t\\n1180\\t/// Validate a PostgreSQL database name to prevent SQL injection in DDL.\\n1181\\t///\\n1182\\t/// PostgreSQL identifiers may contain letters, digits, `_`, and `$`, and\\n1183\\t/// must start with a letter or `_`. We apply a conservative subset of that\\n1184\\t/// rule here to keep things simple and safe.\\n1185\\tfn validate_pg_db_name(name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n1186\\t    if name.is_empty() {\\n1187\\t        return Err(AxonError::InvalidArgument(\\n1188\\t            \\\"database name must not be empty\\\".to_owned(),\\n1189\\t        ));\\n1190\\t    }\\n1191\\t    let first = name.chars().next().expect(\\\"non-empty checked above\\\");\\n1192\\t    if !first.is_ascii_alphabetic() \u0026\u0026 first != '_' {\\n1193\\t        return Err(AxonError::InvalidArgument(format!(\\n1194\\t            \\\"database name '{name}' must start with a letter or underscore\\\"\\n1195\\t        )));\\n1196\\t    }\\n1197\\t    if !name.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {\\n1198\\t        return Err(AxonError::InvalidArgument(format!(\\n1199\\t            \\\"database name '{name}' contains invalid characters (only ASCII alphanumeric and _ allowed)\\\"\\n1200\\t        )));\\n1201\\t    }\\n1202\\t    Ok(())\\n1203\\t}\\n1204\\t\\n1205\\t/// Derive a per-tenant DSN from a superadmin DSN by replacing/adding the\\n1206\\t/// `dbname` key.\\n1207\\t///\\n1208\\t/// The superadmin DSN uses the `postgres` maintenance database.  We produce a\\n1209\\t/// new DSN that targets `axon_{name}`.\\n1210\\t///\\n1211\\t/// Both libpq keyword–value format (`host=... dbname=...`) and URL format\\n1212\\t/// (`postgres://...`) are supported.\\n1213\\tpub fn tenant_dsn(superadmin_dsn: \u0026str, tenant_db_name: \u0026str) -\u003e String {\\n1214\\t    let target = format!(\\\"axon_{tenant_db_name}\\\");\\n1215\\t    if superadmin_dsn.starts_with(\\\"postgres://\\\") || superadmin_dsn.starts_with(\\\"postgresql://\\\") {\\n1216\\t        // URL format: replace path component.\\n1217\\t        // e.g. postgres://user:pass@host/somedb?sslmode=disable\\n1218\\t        if let Some(pos) = superadmin_dsn.find(\\\"://\\\") {\\n1219\\t            let after_scheme = \u0026superadmin_dsn[pos + 3..];\\n1220\\t            // Find the slash that separates authority from path.\\n1221\\t            if let Some(slash_pos) = after_scheme.find('/') {\\n1222\\t                let scheme_authority = \u0026superadmin_dsn[..pos + 3 + slash_pos];\\n1223\\t                let rest = \u0026after_scheme[slash_pos + 1..];\\n1224\\t                // Strip existing dbname (everything before '?').\\n1225\\t                let query = if let Some(q) = rest.find('?') {\\n1226\\t                    \u0026rest[q..]\\n1227\\t                } else {\\n1228\\t                    \\\"\\\"\\n1229\\t                };\\n1230\\t                return format!(\\\"{scheme_authority}/{target}{query}\\\");\\n1231\\t            }\\n1232\\t            // No path: append the target database.\\n1233\\t            return format!(\\\"{superadmin_dsn}/{target}\\\");\\n1234\\t        }\\n1235\\t        format!(\\\"{superadmin_dsn}/{target}\\\")\\n1236\\t    } else {\\n1237\\t        // Keyword–value format.  Replace existing dbname= or append it.\\n1238\\t        let mut parts: Vec\u003cString\u003e = superadmin_dsn\\n1239\\t            .split_whitespace()\\n1240\\t            .filter(|part| !part.starts_with(\\\"dbname=\\\"))\\n1241\\t            .map(str::to_owned)\\n1242\\t            .collect();\\n1243\\t        parts.push(format!(\\\"dbname={target}\\\"));\\n1244\\t        parts.join(\\\" \\\")\\n1245\\t    }\\n1246\\t}\\n1247\\t\\n1248\\t/// Create a physical PostgreSQL database named `axon_{name}` using a\\n1249\\t/// superadmin connection.\\n1250\\t///\\n1251\\t/// The `superadmin_dsn` must connect to the `postgres` maintenance database\\n1252\\t/// (or any database the superuser can reach) with sufficient privileges to\\n1253\\t/// execute `CREATE DATABASE`.\\n1254\\t///\\n1255\\t/// The database name is validated to prevent SQL injection.\\n1256\\t///\\n1257\\t/// # Errors\\n1258\\t///\\n1259\\t/// Returns `AxonError::AlreadyExists` if the database already exists.\\n1260\\t/// Returns `AxonError::InvalidArgument` if `name` contains invalid characters.\\n1261\\t/// Returns `AxonError::Storage` for other PostgreSQL errors.\\n1262\\tpub fn provision_postgres_database(superadmin_dsn: \u0026str, name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n1263\\t    validate_pg_db_name(name)?;\\n1264\\t    let full_name = format!(\\\"axon_{name}\\\");\\n1265\\t    let rt = tokio::runtime::Builder::new_current_thread()\\n1266\\t        .enable_all()\\n1267\\t        .build()\\n1268\\t        .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1269\\t    rt.block_on(async {\\n1270\\t        let (client, connection) = tokio_postgres::connect(superadmin_dsn, NoTls)\\n1271\\t            .await\\n1272\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1273\\t        tokio::spawn(async move {\\n1274\\t            let _ = connection.await;\\n1275\\t        });\\n1276\\t        let row = client\\n1277\\t            .query_one(\\n1278\\t                \\\"SELECT EXISTS(SELECT 1 FROM pg_database WHERE datname = $1)\\\",\\n1279\\t                \u0026[\u0026full_name.as_str()],\\n1280\\t            )\\n1281\\t            .await\\n1282\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1283\\t        let exists: bool = row.get(0);\\n1284\\t        if exists {\\n1285\\t            return Err(AxonError::AlreadyExists(format!(\\n1286\\t                \\\"PostgreSQL database '{full_name}'\\\"\\n1287\\t            )));\\n1288\\t        }\\n1289\\t        // CREATE DATABASE cannot run inside a transaction; use simple_query to\\n1290\\t        // avoid the implicit transaction that execute() would open.\\n1291\\t        client\\n1292\\t            .simple_query(\u0026format!(\\\"CREATE DATABASE \\\\\\\"{full_name}\\\\\\\"\\\"))\\n1293\\t            .await\\n1294\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1295\\t        Ok(())\\n1296\\t    })\\n1297\\t}\\n1298\\t\\n1299\\t/// Drop the physical PostgreSQL database named `axon_{name}`.\\n1300\\t///\\n1301\\t/// The `superadmin_dsn` must have sufficient privileges to execute\\n1302\\t/// `DROP DATABASE`.\\n1303\\t///\\n1304\\t/// # Errors\\n1305\\t///\\n1306\\t/// Returns `AxonError::NotFound` if the database does not exist.\\n1307\\t/// Returns `AxonError::InvalidArgument` if `name` contains invalid characters.\\n1308\\t/// Returns `AxonError::Storage` for other PostgreSQL errors.\\n1309\\tpub fn deprovision_postgres_database(superadmin_dsn: \u0026str, name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n1310\\t    validate_pg_db_name(name)?;\\n1311\\t    let full_name = format!(\\\"axon_{name}\\\");\\n1312\\t    let rt = tokio::runtime::Builder::new_current_thread()\\n1313\\t        .enable_all()\\n1314\\t        .build()\\n1315\\t        .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1316\\t    rt.block_on(async {\\n1317\\t        let (client, connection) = tokio_postgres::connect(superadmin_dsn, NoTls)\\n1318\\t            .await\\n1319\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1320\\t        tokio::spawn(async move {\\n1321\\t            let _ = connection.await;\\n1322\\t        });\\n1323\\t        let row = client\\n1324\\t            .query_one(\\n1325\\t                \\\"SELECT EXISTS(SELECT 1 FROM pg_database WHERE datname = $1)\\\",\\n1326\\t                \u0026[\u0026full_name.as_str()],\\n1327\\t            )\\n1328\\t            .await\\n1329\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1330\\t        let exists: bool = row.get(0);\\n1331\\t        if !exists {\\n1332\\t            return Err(AxonError::NotFound(format!(\\n1333\\t                \\\"PostgreSQL database '{full_name}'\\\"\\n1334\\t            )));\\n1335\\t        }\\n1336\\t        client\\n1337\\t            .simple_query(\u0026format!(\\\"DROP DATABASE \\\\\\\"{full_name}\\\\\\\"\\\"))\\n1338\\t            .await\\n1339\\t            .map_err(|e| AxonError::Storage(e.to_string()))?;\\n1340\\t        Ok(())\\n1341\\t    })\\n1342\\t}\\n1343\\t\\n1344\\t// The conformance test suite requires PostgreSQL.\\n1345\\t// Explicit verification path:\\n1346\\t// AXON_TEST_POSTGRES=\\\"host=localhost user=axon dbname=axon_test\\\" cargo test -p axon-storage postgres::tests:: -- --nocapture\\n1347\\t// When `AXON_TEST_POSTGRES` is unset, these tests attempt to provision PostgreSQL\\n1348\\t// via testcontainers and skip cleanly if the container runtime is unavailable.\\n1349\\t#[cfg(test)]\\n1350\\tmod tests {\\n1351\\t    use std::{\\n1352\\t        ops::{Deref, DerefMut},\\n1353\\t        sync::{Mutex, MutexGuard, OnceLock},\\n1354\\t    };\\n1355\\t\\n1356\\t    use super::*;\\n1357\\t    use axon_core::types::Link;\\n1358\\t    use testcontainers_modules::postgres::Postgres as PgContainer;\\n1359\\t    use testcontainers_modules::testcontainers::{runners::SyncRunner, Container};\\n1360\\t\\n1361\\t    struct TestDatabase {\\n1362\\t        url: String,\\n1363\\t        _container: Option\u003cContainer\u003cPgContainer\u003e\u003e,\\n1364\\t    }\\n1365\\t\\n1366\\t    enum TestSetupError {\\n1367\\t        Skip(String),\\n1368\\t        Fail(AxonError),\\n1369\\t    }\\n1370\\t\\n1371\\t    impl TestDatabase {\\n1372\\t        fn connect() -\u003e Result\u003cSelf, TestSetupError\u003e {\\n1373\\t            if let Ok(url) = std::env::var(\\\"AXON_TEST_POSTGRES\\\") {\\n1374\\t                return Ok(Self {\\n1375\\t                    url,\\n1376\\t                    _container: None,\\n1377\\t                });\\n1378\\t            }\\n1379\\t\\n1380\\t            let container = PgContainer::default()\\n1381\\t                .with_db_name(\\\"axon_test\\\")\\n1382\\t                .with_user(\\\"postgres\\\")\\n1383\\t                .with_password(\\\"postgres\\\")\\n1384\\t                .start()\\n1385\\t                .map_err(|error| {\\n1386\\t                    TestSetupError::Skip(format!(\\n1387\\t                        \\\"AXON_TEST_POSTGRES is unset and PostgreSQL test container startup failed: {error}\\\"\\n1388\\t                    ))\\n1389\\t                })?;\\n1390\\t            let host = container.get_host().map_err(|error| {\\n1391\\t                TestSetupError::Fail(AxonError::Storage(format!(\\n1392\\t                    \\\"failed to resolve PostgreSQL test container host: {error}\\\"\\n1393\\t                )))\\n1394\\t            })?;\\n1395\\t            let port = container.get_host_port_ipv4(5432).map_err(|error| {\\n1396\\t                TestSetupError::Fail(AxonError::Storage(format!(\\n1397\\t                    \\\"failed to resolve PostgreSQL test container port: {error}\\\"\\n1398\\t                )))\\n1399\\t            })?;\\n1400\\t\\n1401\\t            Ok(Self {\\n1402\\t                url: format!(\\n1403\\t                    \\\"host={host} port={port} user=postgres password=postgres dbname=axon_test\\\"\\n1404\\t                ),\\n1405\\t                _container: Some(container),\\n1406\\t            })\\n1407\\t        }\\n1408\\t\\n1409\\t        fn url(\u0026self) -\u003e \u0026str {\\n1410\\t            \u0026self.url\\n1411\\t        }\\n1412\\t    }\\n1413\\t\\n1414\\t    struct TestStore {\\n1415\\t        adapter: PostgresStorageAdapter,\\n1416\\t        _database: TestDatabase,\\n1417\\t    }\\n1418\\t\\n1419\\t    impl Deref for TestStore {\\n1420\\t        type Target = PostgresStorageAdapter;\\n1421\\t\\n1422\\t        fn deref(\u0026self) -\u003e \u0026Self::Target {\\n1423\\t            \u0026self.adapter\\n1424\\t        }\\n1425\\t    }\\n1426\\t\\n1427\\t    impl DerefMut for TestStore {\\n1428\\t        fn deref_mut(\u0026mut self) -\u003e \u0026mut Self::Target {\\n1429\\t            \u0026mut self.adapter\\n1430\\t        }\\n1431\\t    }\\n1432\\t\\n1433\\t    fn postgres_test_guard() -\u003e MutexGuard\u003c'static, ()\u003e {\\n1434\\t        static GUARD: OnceLock\u003cMutex\u003c()\u003e\u003e = OnceLock::new();\\n1435\\t        GUARD\\n1436\\t            .get_or_init(|| Mutex::new(()))\\n1437\\t            .lock()\\n1438\\t            .expect(\\\"PostgreSQL test guard lock should not be poisoned\\\")\\n1439\\t    }\\n1440\\t\\n1441\\t    fn skip_postgres_test(test_name: \u0026str, reason: \u0026str) {\\n1442\\t        tracing::warn!(test = test_name, reason, \\\"skipping PostgreSQL storage test\\\");\\n1443\\t    }\\n1444\\t\\n1445\\t    fn database_or_skip(test_name: \u0026str) -\u003e Option\u003cTestDatabase\u003e {\\n1446\\t        match TestDatabase::connect() {\\n1447\\t            Ok(database) =\u003e Some(database),\\n1448\\t            Err(TestSetupError::Skip(reason)) =\u003e {\\n1449\\t                skip_postgres_test(test_name, \u0026reason);\\n1450\\t                None\\n1451\\t            }\\n1452\\t            Err(TestSetupError::Fail(error)) =\u003e {\\n1453\\t                panic!(\\\"PostgreSQL test setup should succeed: {error}\\\");\\n1454\\t            }\\n1455\\t        }\\n1456\\t    }\\n1457\\t\\n1458\\t    fn store() -\u003e Result\u003cTestStore, TestSetupError\u003e {\\n1459\\t        let database = TestDatabase::connect()?;\\n1460\\t        let adapter =\\n1461\\t            PostgresStorageAdapter::connect(database.url()).map_err(TestSetupError::Fail)?;\\n1462\\t        // Clean tables for a fresh test.\\n1463\\t        adapter\\n1464\\t            .block(adapter.client.batch_execute(\\n1465\\t                \\\"TRUNCATE entities, schemas, collection_views, collections, namespaces, databases, audit_log RESTART IDENTITY CASCADE\\\",\\n1466\\t            ))\\n1467\\t            .map_err(TestSetupError::Fail)?;\\n1468\\t        adapter\\n1469\\t            .ensure_default_namespace()\\n1470\\t            .map_err(TestSetupError::Fail)?;\\n1471\\t        Ok(TestStore {\\n1472\\t            adapter,\\n1473\\t            _database: database,\\n1474\\t        })\\n1475\\t    }\\n1476\\t\\n1477\\t    fn store_or_skip(test_name: \u0026str) -\u003e Option\u003cTestStore\u003e {\\n1478\\t        match store() {\\n1479\\t            Ok(store) =\u003e Some(store),\\n1480\\t            Err(TestSetupError::Skip(reason)) =\u003e {\\n1481\\t                skip_postgres_test(test_name, \u0026reason);\\n1482\\t                None\\n1483\\t            }\\n1484\\t            Err(TestSetupError::Fail(error)) =\u003e {\\n1485\\t                panic!(\\\"PostgreSQL test setup should succeed: {error}\\\");\\n1486\\t            }\\n1487\\t        }\\n1488\\t    }\\n1489\\t\\n1490\\t    fn register_unique_namespaced_collection(\\n1491\\t        store: \u0026mut TestStore,\\n1492\\t        qualified: \u0026CollectionId,\\n1493\\t    ) -\u003e (Namespace, CollectionId) {\\n1494\\t        let (namespace, bare_collection) = Namespace::parse(qualified.as_str());\\n1495\\t        let bare_collection = CollectionId::new(bare_collection);\\n1496\\t\\n1497\\t        store\\n1498\\t            .create_database(namespace.database.as_str())\\n1499\\t            .expect(\\\"database create should succeed\\\");\"}]},\"parent_tool_use_id\":\"toolu_01V9ewrQMRMUNg8o8KExVgdR\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"16ba58da-8642-47e8-be12-7f712623b69f\",\"timestamp\":\"2026-04-15T01:31:04.617Z\"}\n{\"type\":\"system\",\"subtype\":\"task_progress\",\"task_id\":\"ab7893c6e8bebbea1\",\"tool_use_id\":\"toolu_01TSMSYvQzdh78YH3Sxyiy8q\",\"description\":\"Reading docs/helix/02-design/adr/ADR-018-tenant-user-credential-model.md\",\"usage\":{\"total_tokens\":30020,\"tool_uses\":18,\"duration_ms\":14448},\"last_tool_name\":\"Read\",\"uuid\":\"8afa7152-23b1-425e-bc05-780ebec17bd7\",\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-haiku-4-5-20251001\",\"id\":\"msg_011SNRZDMg65PuYWAEQgKe6a\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_01Uzmkp7MEZPni2mXrvk8UYL\",\"name\":\"Read\",\"input\":{\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T0130